#import "MyCell.h"

@implementation MyCell

- (instancetype)initWithFrame:(CGRect)frame {
    self = [super initWithFrame:frame];
    if (self) {
        [self setupUI];
    }
    return self;
}

- (void)setupUI {
    self.containerView = [[UIView alloc] init];
    [self.contentView addSubview:self.containerView];

    self.cardImageView = [[UIImageView alloc] init];
    self.cardImageView.contentMode = UIViewContentModeScaleToFill;
    self.cardImageView.hidden = YES;
    [self.containerView addSubview:self.cardImageView];

    self.containerView.backgroundColor = RGBA(245, 245, 245, 1);
    self.containerView.layer.cornerRadius = ZOOMW(24);
    self.containerView.layer.borderWidth = 1;
    self.containerView.layer.borderColor = RGBA(61, 157, 255, 1).CGColor;

    self.iconView = [[UIImageView alloc] init];
    self.iconView.contentMode = UIViewContentModeScaleAspectFit;
    self.iconView.tintColor = RGBA(61, 157, 255, 1);
    [self.containerView addSubview:self.iconView];

    self.titleLabel = [[UILabel alloc] init];
    self.titleLabel.font = KEEPASS_FONT_Medium(18);
    self.titleLabel.textColor = RGBA(51, 51, 51, 1);
    self.titleLabel.textAlignment = NSTextAlignmentCenter;
    [self.containerView addSubview:self.titleLabel];

    [self setupConstraints];
}

- (void)setupConstraints {
    [self.containerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.equalTo(self.contentView);
    }];

    [self.cardImageView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.equalTo(self.containerView);
    }];

    [self.iconView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerX.equalTo(self.containerView);
        make.centerY.equalTo(self.containerView).offset(ZOOMW(-12));
        make.width.height.mas_equalTo(ZOOMW(36));
    }];

    [self.titleLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.containerView).offset(ZOOMW(16));
        make.right.equalTo(self.containerView).offset(ZOOMW(-16));
        make.bottom.equalTo(self.containerView).offset(ZOOMW(-18));
    }];
}

- (void)configureWithCardImageName:(NSString *)cardImageName
                          iconName:(NSString *)iconName
                             title:(NSString *)title {
    UIImage *cardImage = cardImageName.length > 0 ? [UIImage imageNamed:cardImageName] : nil;
    self.cardImageView.image = cardImage;
    self.cardImageView.hidden = (cardImage == nil);

    BOOL useCardImage = (cardImage != nil);
    self.iconView.hidden = useCardImage;
    self.titleLabel.hidden = useCardImage;

    if (useCardImage) {
        self.containerView.backgroundColor = CLEAR_COLOR;
        self.containerView.layer.cornerRadius = 0;
        self.containerView.layer.borderWidth = 0;
        self.containerView.layer.borderColor = CLEAR_COLOR.CGColor;
        self.titleLabel.text = @"";
        self.iconView.image = nil;
        return;
    }

    self.containerView.backgroundColor = RGBA(245, 245, 245, 1);
