@implementation SettingViewController

- (void)viewDidLoad {
    [super viewDidLoad];
    self.title = @"Set";
    UIImage *backImg = [UIImage imageNamed:@"LH_setting_back"];
    if (backImg) {
        UIImage *returnImage = [[backImg imageByResizeToSize:CGSizeMake(ZOOM(24), ZOOM(24)) contentMode:UIViewContentModeScaleAspectFit] imageWithRenderingMode:UIImageRenderingModeAlwaysOriginal];
        self.navigationItem.leftBarButtonItem = [[UIBarButtonItem alloc] initWithImage:returnImage style:UIBarButtonItemStylePlain target:self action:@selector(returnButtonClicked)];
    }
    [self setupUI];
}


#pragma mark - setupUI

- (void)setupUI {
    self.view.backgroundColor = WHITE_COLOR;
    [self addAllSubviews];
    [self addAllConstraints];
}

- (void)addAllSubviews {
    [self.view addSubview:self.clearView];
    [self.clearView addSubview:self.clearLabel];
    [self.clearView addSubview:self.goView_1];
}

- (void)addAllConstraints {
    [_clearView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.view).offset(ZOOMW(20));
        make.left.right.equalTo(self.view).inset(ZOOMW(16));
        make.height.mas_equalTo(ZOOMW(56));
    }];

    [_clearLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(self.clearView);
        make.left.equalTo(self.clearView).offset(ZOOMW(16));
    }];

    [_goView_1 mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(self.clearView);
        make.right.equalTo(self.clearView).offset(ZOOMW(-16));
        make.width.height.mas_equalTo(ZOOMW(20));
    }];
}


#pragma mark - events

- (void)returnButtonClicked {
    [self.navigationController popViewControllerAnimated:YES];
}

- (void)inistate {
    UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"Clear All Chat History" message:@"Chat history cannot be recovered once cleared" preferredStyle:UIAlertControllerStyleAlert];
    UIAlertAction *cancel = [UIAlertAction actionWithTitle:@"Cancel" style:UIAlertActionStyleCancel handler:nil];
    UIAlertAction *confirm = [UIAlertAction actionWithTitle:@"Confirm" style:UIAlertActionStyleDestructive handler:^(UIAlertAction * _Nonnull action) {

#if ENABLE_FEEDBACK

#else
        [FeedbackModel clearMsgs];
#endif

        [SVProgressHUD showSuccessWithStatus:@"Cleared successfully"];
        [SVProgressHUD dismissWithDelay:0.5];
        [[NSNotificationCenter defaultCenter] postNotificationName:@"Init" object:nil];
        [self.navigationController popViewControllerAnimated:YES];
    }];
    [alert addAction:cancel];
    [alert addAction:confirm];
    [self presentViewController:alert animated:YES completion:nil];
}

- (void)clearSuccess {
    [[NSURLCache sharedURLCache] removeAllCachedResponses];
    [SVProgressHUD showSuccessWithStatus:@"Cleared successfully"];
    [SVProgressHUD dismissWithDelay:0.5];
}


#pragma mark - lazy

- (UIView *)clearView {
    if (_clearView == nil) {
        _clearView = [[UIView alloc] init];
        _clearView.backgroundColor = RGBA(245, 245, 245, 1);
        _clearView.layer.cornerRadius = ZOOMW(28);
        UITapGestureRecognizer *tapGesture = [[UITapGestureRecognizer alloc] initWithTarget:self action:@selector(clearSuccess)];
        tapGesture.cancelsTouchesInView = NO; // 不取消其他触摸事件
        [self.clearView addGestureRecognizer:tapGesture];
    }
    return _clearView;
}

- (UILabel *)clearLabel {
    if (_clearLabel == nil) {
        _clearLabel = [[UILabel alloc] init];
        _clearLabel.text = @"Clear cache";
        _clearLabel.textColor = RGBA(51, 51, 51, 1);
        _clearLabel.font = KEEPASS_FONT_Regular(16);
    }
    return _clearLabel;
}

- (UIImageView *)goView_1 {
    if (_goView_1 == nil) {
        _goView_1 = [[UIImageView alloc] init];
        _goView_1.image = [[UIImage imageNamed:@"LH_setting_go"] imageWithRenderingMode:UIImageRenderingModeAlwaysOriginal];
    }
    return _goView_1;
}

@end

